#include <stdio.h>
#include <stdint.h>
#define MOD 1000000007

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int64_t L, R;
        scanf("%lld %lld", &L, &R);
        int64_t N = R - L + 1;
        int64_t dp[N][N] = {0};
        dp[0][0] = 1;
        int64_t K = 0, C = 0;
        for (int64_t i = 0; i < N; i++) {
            for (int64_t j = 0; j < N; j++) {
                if (i > 0) dp[i][j] += dp[i - 1][j];
                if (j > 0) dp[i][j] += dp[i][j - 1];
                dp[i][j] %= MOD;
                if (i == j && dp[i][j] > 0) {
                    K = i;
                    C = dp[i][j];
                }
            }
        }
        printf("%lld %lld\n", K, C);
    }
    return 0;
}

