    const N = R - L + 1;
    const dp = Array(N).fill(0).map(() => Array(N).fill(0));
    dp[0][0] = 1;
    let K = 0, C = 0;
    for (let j = 0; j < N; j++) {
        for (let k = 0; k < N; k++) {
            if (j > 0) dp[j][k] += dp[j - 1][k];
            if (k > 0) dp[j][k] += dp[j][k - 1];
            dp[j][k] %= 1000000007;
            if (j === k && dp[j][k] > 0) {
                K = j;
                C = dp[j][k];
            }
        }
    }
    console.log(K + ' ' + C);
}

